import { Injectable } from '@angular/core';
import { from, Observable, BehaviorSubject } from 'rxjs'; // 🚀 AJOUT : BehaviorSubject

@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  private apiUrl = 'http://localhost:3000/api/notifications';

  // 🚀 AJOUT : Canal réactif invisible pour mémoriser la candidature à ouvrir au clic
  private openApplicationSubject = new BehaviorSubject<number | null>(null);
  public openApplication$ = this.openApplicationSubject.asObservable();

  private getHeaders() {
    const token = localStorage.getItem('token');
    return {
      'Content-Type': 'application/json',
      'Authorization': token ? `Bearer ${token}` : ''
    };
  }

  // 🚀 AJOUT : Déclenche l'enregistrement de l'ID depuis la cloche
  triggerCandidateModal(applicationId: number) {
    this.openApplicationSubject.next(applicationId);
  }

  // 🚀 AJOUT : Vide la mémoire après l'affichage de la modal pour éviter les boucles
  clearTrigger() {
    this.openApplicationSubject.next(null);
  }

  getNotifications(): Observable<any[]> {
    const promise = fetch(this.apiUrl, {
      method: 'GET',
      headers: this.getHeaders()
    }).then(res => {
      if (!res.ok) throw new Error(res.statusText);
      return res.json();
    });
    return from(promise);
  }

  markAllAsRead(): Observable<any> {
    const promise = fetch(`${this.apiUrl}/read`, {
      method: 'POST',
      headers: this.getHeaders(),
      body: JSON.stringify({})
    }).then(res => {
      if (!res.ok) throw new Error(res.statusText);
      return res.json();
    });
    return from(promise);
  }
}
